import{_ as d,o as a,c as r,a2 as e}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"数据中心+能源 · 赛道文件","description":"","frontmatter":{"updated":"2026-06-23T00:00:00.000Z","visibility":"public"},"headers":[],"relativePath":"算电协同/数据中心+能源/赛道文件.md","filePath":"算电协同/数据中心+能源/赛道文件.md","lastUpdated":1781535932000}'),h={name:"算电协同/数据中心+能源/赛道文件.md"};function o(n,t,s,l,i,b){return a(),r("div",null,[...t[0]||(t[0]=[e(`<h1 id="数据中心-能源-·-赛道文件" tabindex="-1">数据中心+能源 · 赛道文件 <a class="header-anchor" href="#数据中心-能源-·-赛道文件" aria-label="Permalink to &quot;数据中心+能源 · 赛道文件&quot;">​</a></h1><p><strong>成熟度：</strong> 爆发初期（2026 写入政府工作报告，列为新基建工程） <strong>PE/VC 重心：</strong> 绿电直连项目、智算中心运营、DC 需求响应聚合、800V HVDC 电气链路 <strong>数据来源：</strong> websearch, JLL, 国家能源局, 中金数据等公开信息 <strong>数据获取：</strong> 2026-06-15</p><hr><h2 id="一、赛道概览" tabindex="-1">一、赛道概览 <a class="header-anchor" href="#一、赛道概览" aria-label="Permalink to &quot;一、赛道概览&quot;">​</a></h2><h3 id="_1-1-核心逻辑" tabindex="-1">1.1 核心逻辑 <a class="header-anchor" href="#_1-1-核心逻辑" aria-label="Permalink to &quot;1.1 核心逻辑&quot;">​</a></h3><p>数据中心从&quot;用电户&quot;转变为&quot;能源系统参与者&quot;——不仅是电力的消费者，更是新能源消纳的载体、需求响应的灵活性资源、绿证/碳市场的核心买方。</p><blockquote><p><strong>一句话：</strong> 算力的尽头是电力，电力的增量市场在算力。</p></blockquote><h3 id="_1-2-市场规模" tabindex="-1">1.2 市场规模 <a class="header-anchor" href="#_1-2-市场规模" aria-label="Permalink to &quot;1.2 市场规模&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指标</th><th>2025</th><th>2026E</th><th>2028E</th><th>2030E</th></tr></thead><tbody><tr><td>中国 DC 用电量</td><td>1,933亿度</td><td>~2,500亿度</td><td>~4,000亿度</td><td>5,258-7,000亿度</td></tr><tr><td>占全社会用电比</td><td>1.9%</td><td>~2.5%</td><td>~3.5%</td><td>5.3%</td></tr><tr><td>年增速</td><td>17%</td><td>19%+</td><td>—</td><td>—</td></tr><tr><td>全球 DC 投资</td><td>$7,700亿</td><td>—</td><td>—</td><td>—</td></tr><tr><td>DC 核心基金规模</td><td>—</td><td>$500亿+</td><td>—</td><td>—</td></tr><tr><td>中国 REITs</td><td>首批上市</td><td>规模化发行</td><td>—</td><td>—</td></tr></tbody></table><p><strong>核心趋势：</strong> 2026 年政府工作报告首次将算电协同列为新基建工程。截至 2026 年 3 月，已有近 60 家上市公司在年报/互动平台主动提及相关业务。</p><blockquote><p>🔗 数据来源：JLL《2026全球数据中心展望》、国家能源局新闻发布会(2026.04)、中国信通院</p></blockquote><hr><h2 id="二、商业模式全景" tabindex="-1">二、商业模式全景 <a class="header-anchor" href="#二、商业模式全景" aria-label="Permalink to &quot;二、商业模式全景&quot;">​</a></h2><h3 id="_2-1-四种主要路径" tabindex="-1">2.1 四种主要路径 <a class="header-anchor" href="#_2-1-四种主要路径" aria-label="Permalink to &quot;2.1 四种主要路径&quot;">​</a></h3><h4 id="a-绿电直连-当前最成熟" tabindex="-1">A. 绿电直连（当前最成熟） <a class="header-anchor" href="#a-绿电直连-当前最成熟" aria-label="Permalink to &quot;A. 绿电直连（当前最成熟）&quot;">​</a></h4><table tabindex="0"><thead><tr><th>模式</th><th>说明</th><th>代表项目</th><th>经济性</th></tr></thead><tbody><tr><td><strong>单用户专属 (1.0)</strong></td><td>风/光直供单用户</td><td>乌兰察布中金数据（2025.07）</td><td>年自发自用 8.48亿度</td></tr><tr><td><strong>多用户共享 (2.0)</strong></td><td>多主体共享绿电</td><td>大唐中卫（2026.05）</td><td>规划投资~200亿</td></tr><tr><td><strong>源网荷储一体化</strong></td><td>风光储+DC 微网</td><td>华电和林格尔</td><td>年供绿电 7.6亿度，电价 0.36元/度</td></tr></tbody></table><p><strong>政策进展：</strong> 2026 年 5 月，发改委/能源局发文推动绿电直连从 1.0 升级到 2.0，打开多主体共享空间。</p><h4 id="b-智算中心运营" tabindex="-1">B. 智算中心运营 <a class="header-anchor" href="#b-智算中心运营" aria-label="Permalink to &quot;B. 智算中心运营&quot;">​</a></h4><table tabindex="0"><thead><tr><th>玩家</th><th>项目</th><th>绿电占比</th><th>机柜数</th><th>毛利率</th></tr></thead><tbody><tr><td>优刻得</td><td>乌兰察布</td><td>80%</td><td>2,300</td><td><strong>62.7%</strong>（vs 公司整体 18.86%）</td></tr><tr><td>并行科技</td><td>和林格尔</td><td>&gt;80%</td><td>—</td><td>年省电费 630 万</td></tr><tr><td>世纪互联</td><td>乌兰察布</td><td>—</td><td>规划 24万架</td><td>REITs 发行成功</td></tr><tr><td>中联数据</td><td>零碳智算产业园</td><td>—</td><td>24万架/600MW</td><td>—</td></tr></tbody></table><h4 id="c-需求响应-辅助服务" tabindex="-1">C. 需求响应/辅助服务 <a class="header-anchor" href="#c-需求响应-辅助服务" aria-label="Permalink to &quot;C. 需求响应/辅助服务&quot;">​</a></h4><table tabindex="0"><thead><tr><th>方式</th><th>10MW DC 年收益</th><th>说明</th></tr></thead><tbody><tr><td>调峰辅助服务</td><td><strong>20-50万元</strong></td><td>可压减 2-3MW，每周参与 2 次</td></tr><tr><td>现货市场价差套利</td><td><strong>30-80万元</strong></td><td>转移批处理任务，利用谷电价</td></tr><tr><td>绿电直供电价节省</td><td><strong>400-900万元</strong></td><td>节省 0.05-0.10元/度，核心收益来源</td></tr></tbody></table><blockquote><p>💡 详细测算见 <code>_深化_2026-06-13_数据中心需求响应收益测算.md</code></p></blockquote><h4 id="d-电气链路重构-前沿方向" tabindex="-1">D. 电气链路重构（前沿方向） <a class="header-anchor" href="#d-电气链路重构-前沿方向" aria-label="Permalink to &quot;D. 电气链路重构（前沿方向）&quot;">​</a></h4><table tabindex="0"><thead><tr><th>技术</th><th>说明</th><th>阶段</th><th>投资机会</th></tr></thead><tbody><tr><td>800V HVDC</td><td>打通发电侧到负载侧全链路直流</td><td>灰度验证/工程试点</td><td>电力电子设备</td></tr><tr><td>液冷散热</td><td>降低 PUE，减少电费</td><td>规模化部署中</td><td>液冷设备供应商</td></tr><tr><td>余热回收</td><td>数据中心余热用于供暖</td><td>试点阶段</td><td>区域供热模式</td></tr></tbody></table><hr><h2 id="三、关键政策节点" tabindex="-1">三、关键政策节点 <a class="header-anchor" href="#三、关键政策节点" aria-label="Permalink to &quot;三、关键政策节点&quot;">​</a></h2><table tabindex="0"><thead><tr><th>时间</th><th>政策/事件</th><th>影响</th></tr></thead><tbody><tr><td>2025.07</td><td>乌兰察布中金数据首个 DC 绿电直连投运</td><td>示范效应</td></tr><tr><td>2025.09</td><td>发改委/能源局发文建立按容（需）量收取输配电费机制</td><td>大幅降低绿电直连中间成本</td></tr><tr><td>2026.02</td><td>绿电直连 84 项目完成审批，总装机 32.59 GW</td><td>规模扩大</td></tr><tr><td>2026.03</td><td>算电协同写入政府工作报告</td><td>政策顶层认可</td></tr><tr><td>2026.04</td><td>国家能源局将算力设施列入电力保供重点领域</td><td>明确优先级</td></tr><tr><td>2026.05</td><td>大唐中卫全国首个大规模算电协同项目并网</td><td>标杆项目</td></tr><tr><td>2026.05</td><td>多用户绿电直连政策（绿电直连 2.0）</td><td>打开规模空间</td></tr><tr><td>2026</td><td>内蒙古/河北/浙江/湖南等省发布绿电直连实施方案</td><td>地方细则落地</td></tr></tbody></table><hr><h2 id="四、pe-vc-标的" tabindex="-1">四、PE/VC 标的 <a class="header-anchor" href="#四、pe-vc-标的" aria-label="Permalink to &quot;四、PE/VC 标的&quot;">​</a></h2><h3 id="_4-1-已确认收入的标的" tabindex="-1">4.1 已确认收入的标的 <a class="header-anchor" href="#_4-1-已确认收入的标的" aria-label="Permalink to &quot;4.1 已确认收入的标的&quot;">​</a></h3><table tabindex="0"><thead><tr><th>公司</th><th>方向</th><th>年收入/节省</th><th>阶段</th><th>可投资性</th></tr></thead><tbody><tr><td><strong>华电新能</strong> (600930)</td><td>风光直供 DC</td><td><strong>~2.7亿/年</strong>（项目收益）</td><td>上市公司</td><td>Pre-IPO/定增</td></tr><tr><td><strong>优刻得</strong> (688158)</td><td>智算中心运营</td><td><strong>1.73亿毛利/年</strong>（乌兰察布）</td><td>上市公司</td><td>成长股</td></tr><tr><td><strong>并行科技</strong> (839493.BJ)</td><td>算力租赁</td><td><strong>630万节省/年</strong></td><td>新三板</td><td>观测中</td></tr><tr><td><strong>世纪互联</strong></td><td>DC+REITs</td><td>已发行两单 IDC REITs</td><td>Pre-IPO</td><td>资产证券化</td></tr></tbody></table><h3 id="_4-2-早期投资标的" tabindex="-1">4.2 早期投资标的 <a class="header-anchor" href="#_4-2-早期投资标的" aria-label="Permalink to &quot;4.2 早期投资标的&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方向</th><th>代表公司</th><th>阶段</th><th>说明</th></tr></thead><tbody><tr><td>绿电直连项目开发</td><td>大唐/华电/中金/远景</td><td>运营中</td><td>重资产，适合产业资本</td></tr><tr><td>DC 需求响应聚合</td><td>多家创业公司</td><td>天使-A轮</td><td>轻资产，平台模式</td></tr><tr><td>800V HVDC 设备</td><td>已有电力电子团队</td><td>早期</td><td>技术壁垒高</td></tr><tr><td>DC 液冷方案</td><td>多家供应商</td><td>A-C轮</td><td>确定性高</td></tr><tr><td>DC 碳管理/绿证</td><td>碳阻迹等</td><td>A-B轮</td><td>交叉赛道</td></tr></tbody></table><h3 id="_4-3-商业模式可投资性评分" tabindex="-1">4.3 商业模式可投资性评分 <a class="header-anchor" href="#_4-3-商业模式可投资性评分" aria-label="Permalink to &quot;4.3 商业模式可投资性评分&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模式</th><th>收入确定性</th><th>可规模化</th><th>PE/VC 时机</th><th>推荐度</th></tr></thead><tbody><tr><td>绿电直连项目（资产型）</td><td>⭐⭐⭐⭐⭐</td><td>⭐⭐⭐</td><td>适合产业资本/Pre-IPO</td><td>✅</td></tr><tr><td>智算中心运营（算力出租）</td><td>⭐⭐⭐⭐</td><td>⭐⭐⭐⭐</td><td>高增长，适合成长期</td><td>✅✅</td></tr><tr><td>VPP/需求响应平台（技术型）</td><td>⭐⭐⭐</td><td>⭐⭐⭐⭐⭐</td><td>早期，天使/A轮</td><td>✅✅✅</td></tr><tr><td>电气链路/液冷（设备型）</td><td>⭐⭐⭐⭐</td><td>⭐⭐⭐⭐</td><td>A-C轮</td><td>✅✅</td></tr><tr><td>DC 碳管理 SaaS</td><td>⭐⭐⭐⭐</td><td>⭐⭐⭐⭐⭐</td><td>A-B轮</td><td>✅✅</td></tr></tbody></table><hr><h2 id="五、关键指标" tabindex="-1">五、关键指标 <a class="header-anchor" href="#五、关键指标" aria-label="Permalink to &quot;五、关键指标&quot;">​</a></h2><h3 id="_5-1-数据中心绿电经济性阈值" tabindex="-1">5.1 数据中心绿电经济性阈值 <a class="header-anchor" href="#_5-1-数据中心绿电经济性阈值" aria-label="Permalink to &quot;5.1 数据中心绿电经济性阈值&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>风电直供 DC 最低电价：0.2583元/度（8%资本金 IRR）</span></span>
<span class="line"><span>                  ↓</span></span>
<span class="line"><span>与西部现货电价（甘肃 0.145元/度）差距：~0.11元/度</span></span>
<span class="line"><span>                  ↓</span></span>
<span class="line"><span>差价 = 绿电直连相对现货的&quot;经济性劣势&quot;</span></span>
<span class="line"><span>                  ↓</span></span>
<span class="line"><span>需通过：输配电费减免 + 容量电价补偿 + 碳收益 补平</span></span></code></pre></div><blockquote><p>经济性正在快速改善：按容量收取输配电费新机制已出台，绿电直连 2.0 降低中间成本约 0.03-0.05元/度。</p></blockquote><h3 id="_5-2-dc-灵活性潜力" tabindex="-1">5.2 DC 灵活性潜力 <a class="header-anchor" href="#_5-2-dc-灵活性潜力" aria-label="Permalink to &quot;5.2 DC 灵活性潜力&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指标</th><th>数值</th><th>来源</th></tr></thead><tbody><tr><td>2030年DC电力负荷</td><td>1.05亿千瓦</td><td>北京理工大学</td></tr><tr><td>2030年DC灵活性资源</td><td>2.3-4.0万 MW</td><td>BIT 期刊</td></tr><tr><td>2030年碳减排潜力</td><td>43.4%</td><td>测算</td></tr><tr><td>运行成本降幅</td><td>35.3%</td><td>测算</td></tr></tbody></table><hr><h2 id="六、交叉链接" tabindex="-1">六、交叉链接 <a class="header-anchor" href="#六、交叉链接" aria-label="Permalink to &quot;六、交叉链接&quot;">​</a></h2><table tabindex="0"><thead><tr><th>关联赛道</th><th>链接</th><th>说明</th></tr></thead><tbody><tr><td><strong>算电协同</strong></td><td><a href="./../赛道总览">赛道总览</a></td><td>DC+能源是算电协同核心场景</td></tr><tr><td><strong>储能</strong></td><td><a href="./../../电力新能源/储能/产业链">产业链</a></td><td>DC 储能配套——关键调节资源</td></tr><tr><td><strong>智能电网/VPP</strong></td><td><a href="./../../电力新能源/智能电网/新兴赛道">新兴赛道</a></td><td>DC 是 VPP 的新兴聚合资源</td></tr><tr><td><strong>碳市场</strong></td><td><a href="./../../电力新能源/碳市场/赛道文件">赛道文件</a></td><td>DC 是所有碳管理/绿证的核心买方</td></tr></tbody></table><hr><p><em>创建：2026-06-15 | 整合自 <code>_深化_2026-06-13_数据中心需求响应收益测算.md</code> 及最新政策数据</em></p>`,47)])])}const u=d(h,[["render",o]]);export{p as __pageData,u as default};
